import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import * as api from '../../utils/api';

const GraphViz = ({ highlightPath = [] }) => {
  const svgRef   = useRef();
  const [data, setData]     = useState({ nodes: [], links: [] });
  const [loading, setLoading] = useState(true);
  const [error, setError]   = useState(null);
  const [tooltip, setTooltip] = useState(null);
  const [stats, setStats]   = useState(null);

  useEffect(() => {
    loadGraph();
  }, []);

  useEffect(() => {
    if (!loading && data.nodes.length > 0) drawGraph();
  }, [data, highlightPath, loading]);

  const loadGraph = async () => {
    try {
      setLoading(true);

      // Load hospitals with high limit + edges in parallel
      const [edgesRes, hospitalsRes] = await Promise.all([
        // Limit edges to 500 for performance in browser
        api.getGraphEdges(),
        // Load up to 500 hospitals for graph display
        api.getHospitals({ limit: 500 }),
      ]);

      const hospitals = hospitalsRes.data.data || [];
      const edges     = edgesRes.data.data     || [];

      setStats({ hospitals: hospitalsRes.data.total, edges: edgesRes.data.count });

      // Build node map from hospitals
      const nodeMap = new Map(hospitals.map(h => [h.nodeId, h]));

      // Collect all nodeIds referenced in edges
      const allNodeIds = new Set(edges.flatMap(e => [e.fromNodeId, e.toNodeId]));

      // Build nodes — only hospitals that appear in edges OR all hospitals if no edges
      let nodes;
      if (edges.length === 0) {
        // No edges: show all loaded hospitals as standalone nodes
        nodes = hospitals.filter(h => h.nodeId).map(h => ({ id: h.nodeId, ...h }));
      } else {
        // Only show nodes that have edges AND exist in our hospitals list
        // (limit to 300 nodes max for browser performance)
        const validIds = Array.from(allNodeIds).filter(id => nodeMap.has(id)).slice(0, 300);
        nodes = validIds.map(id => ({ id, ...nodeMap.get(id) }));
      }

      // Deduplicate edges, only keep edges where both nodes are in our nodes list
      const nodeIdSet = new Set(nodes.map(n => n.id));
      const seen      = new Set();
      const links     = edges
        .filter(e => nodeIdSet.has(e.fromNodeId) && nodeIdSet.has(e.toNodeId))
        .filter(e => {
          const key = [e.fromNodeId, e.toNodeId].sort().join('|');
          if (seen.has(key)) return false;
          seen.add(key);
          return true;
        })
        .map(e => ({ source: e.fromNodeId, target: e.toNodeId, distance: e.distanceKm, time: e.travelTimeMinutes }))
        .slice(0, 800); // cap links for performance

      setData({ nodes, links });
    } catch (err) {
      console.error(err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const drawGraph = () => {
    const container = svgRef.current?.parentElement;
    if (!container) return;
    const W = container.clientWidth || 900;
    const H = 560;

    d3.select(svgRef.current).selectAll('*').remove();

    const svg = d3.select(svgRef.current).attr('width', W).attr('height', H);

    // Zoom support
    const g = svg.append('g');
    svg.call(
      d3.zoom().scaleExtent([0.1, 4]).on('zoom', (event) => {
        g.attr('transform', event.transform);
      })
    );

    // Glow filter
    const defs = svg.append('defs');
    const glow = defs.append('filter').attr('id', 'glow');
    glow.append('feGaussianBlur').attr('stdDeviation', '3').attr('result', 'coloredBlur');
    const fm = glow.append('feMerge');
    fm.append('feMergeNode').attr('in', 'coloredBlur');
    fm.append('feMergeNode').attr('in', 'SourceGraphic');

    svg.append('rect').attr('width', W).attr('height', H).attr('fill', '#0a1628');

    const { nodes, links } = data;
    if (nodes.length === 0) {
      svg.append('text').attr('x', W/2).attr('y', H/2).attr('text-anchor', 'middle')
        .attr('fill', '#94a3b8').attr('font-size', 14).text('No hospitals in the network yet');
      return;
    }

    // Deep copy nodes so D3 can mutate them
    const simNodes = nodes.map(n => ({ ...n }));
    const nodeById = new Map(simNodes.map(n => [n.id, n]));

    const simLinks = links.map(l => ({
      ...l,
      source: nodeById.get(l.source) || l.source,
      target: nodeById.get(l.target) || l.target,
    }));

    const highlightSet = new Set();
    for (let i = 0; i < highlightPath.length - 1; i++) {
      highlightSet.add([highlightPath[i], highlightPath[i+1]].sort().join('|'));
    }

    // Force simulation — use weaker forces for large graphs
    const isLarge = simNodes.length > 100;
    const simulation = d3.forceSimulation(simNodes)
      .force('link', d3.forceLink(simLinks).id(d => d.id).distance(isLarge ? 30 : 80))
      .force('charge', d3.forceManyBody().strength(isLarge ? -80 : -300))
      .force('center', d3.forceCenter(W/2, H/2))
      .force('collision', d3.forceCollide(isLarge ? 12 : 28))
      .alphaDecay(isLarge ? 0.05 : 0.02); // settle faster for large graphs

    // Links
    const link = g.append('g').selectAll('line').data(simLinks).join('line')
      .attr('stroke', d => {
        const key = [(d.source?.id||d.source), (d.target?.id||d.target)].sort().join('|');
        return highlightSet.has(key) ? '#f59e0b' : 'rgba(0,196,180,0.2)';
      })
      .attr('stroke-width', d => {
        const key = [(d.source?.id||d.source), (d.target?.id||d.target)].sort().join('|');
        return highlightSet.has(key) ? 3 : 1;
      });

    // Distance labels (only show for small graphs or highlighted)
    const linkLabel = g.append('g').selectAll('text').data(simLinks.filter(() => !isLarge)).join('text')
      .attr('fill', 'rgba(148,163,184,0.6)').attr('font-size', 9).attr('text-anchor', 'middle')
      .text(d => d.distance ? `${d.distance}km` : '');

    // Node radius based on graph size
    const r = isLarge ? 7 : 18;

    const node = g.append('g').selectAll('g').data(simNodes).join('g')
      .call(d3.drag()
        .on('start', (e, d) => { if (!e.active) simulation.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
        .on('drag',  (e, d) => { d.fx = e.x; d.fy = e.y; })
        .on('end',   (e, d) => { if (!e.active) simulation.alphaTarget(0); d.fx = null; d.fy = null; })
      )
      .on('mouseenter', (e, d) => setTooltip({ hospital: d, x: e.clientX, y: e.clientY }))
      .on('mouseleave', () => setTooltip(null));

    node.append('circle')
      .attr('r', d => highlightPath.includes(d.id) ? r + 4 : r)
      .attr('fill', d => {
        if (highlightPath.includes(d.id)) return '#f59e0b';
        const av = d.beds?.available ?? 0;
        if (av > 50)  return 'rgba(16,185,129,0.85)';
        if (av > 10)  return 'rgba(0,196,180,0.85)';
        if (av > 0)   return 'rgba(245,158,11,0.85)';
        return 'rgba(239,68,68,0.75)';
      })
      .attr('stroke', d => highlightPath.includes(d.id) ? '#fff' : 'rgba(255,255,255,0.15)')
      .attr('stroke-width', 1.5)
      .attr('filter', d => highlightPath.includes(d.id) ? 'url(#glow)' : '');

    // Only show text labels for small graphs
    if (!isLarge) {
      node.append('text').attr('dy', 4).attr('text-anchor', 'middle')
        .attr('fill', 'white').attr('font-size', 9).attr('font-weight', 700)
        .attr('pointer-events', 'none')
        .text(d => d.beds?.available ?? '');

      node.append('text').attr('dy', 30).attr('text-anchor', 'middle')
        .attr('fill', '#f8fafc').attr('font-size', 10)
        .attr('pointer-events', 'none')
        .text(d => d.name ? d.name.split(' ').slice(0, 2).join(' ') : d.id);
    }

    simulation.on('tick', () => {
      link
        .attr('x1', d => d.source.x).attr('y1', d => d.source.y)
        .attr('x2', d => d.target.x).attr('y2', d => d.target.y);
      linkLabel
        .attr('x', d => (d.source.x + d.target.x)/2)
        .attr('y', d => (d.source.y + d.target.y)/2 - 4);
      node.attr('transform', d => `translate(${d.x},${d.y})`);
    });
  };

  if (loading) return (
    <div className="loading-center" style={{ flexDirection: 'column', gap: 12 }}>
      <div className="spinner" />
      <div style={{ color: 'var(--slate)', fontSize: 13 }}>Loading hospital network...</div>
    </div>
  );

  if (error) return (
    <div style={{ padding: 24, color: 'var(--red)', background: 'rgba(239,68,68,0.08)', borderRadius: 12, textAlign: 'center' }}>
      ⚠ Failed to load graph: {error}
      <div style={{ marginTop: 12 }}>
        <button className="btn btn-outline" onClick={loadGraph} style={{ fontSize: 13 }}>Retry</button>
      </div>
    </div>
  );

  return (
    <div style={{ position: 'relative' }}>
      {/* Stats bar */}
      {stats && (
        <div style={{ display: 'flex', gap: 20, marginBottom: 12, flexWrap: 'wrap', alignItems: 'center' }}>
          <span style={{ fontSize: 13, color: 'var(--teal)', fontWeight: 600 }}>
            🏥 {stats.hospitals} hospitals · ⬡ {stats.edges} graph edges
          </span>
          {data.nodes.length < stats.hospitals && (
            <span style={{ fontSize: 12, color: 'var(--slate)' }}>
              (showing {data.nodes.length} nodes · {data.links.length} edges for performance)
            </span>
          )}
          <span style={{ fontSize: 12, color: 'var(--slate)' }}>Scroll to zoom · Drag to pan · Drag nodes to move</span>
        </div>
      )}

      {/* Legend */}
      <div style={{ display: 'flex', gap: 16, marginBottom: 10, flexWrap: 'wrap' }}>
        {[
          { color: '#10b981', label: '>50 beds' },
          { color: '#00c4b4', label: '10–50 beds' },
          { color: '#f59e0b', label: '1–10 beds' },
          { color: '#ef4444', label: 'No beds' },
        ].map(({ color, label }) => (
          <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
            <div style={{ width: 10, height: 10, borderRadius: '50%', background: color }} />
            <span style={{ fontSize: 12, color: 'var(--slate)' }}>{label}</span>
          </div>
        ))}
      </div>

      <svg ref={svgRef} style={{ borderRadius: 12, border: '1px solid var(--border)', display: 'block', width: '100%', cursor: 'grab' }} />

      {/* Tooltip */}
      {tooltip && (
        <div style={{
          position: 'fixed', left: tooltip.x + 14, top: tooltip.y - 70,
          background: 'var(--navy-light)', border: '1px solid var(--border)',
          borderRadius: 10, padding: '12px 16px', pointerEvents: 'none',
          zIndex: 999, boxShadow: 'var(--shadow)', minWidth: 220,
        }}>
          <div style={{ fontWeight: 600, marginBottom: 3 }}>{tooltip.hospital.name || tooltip.hospital.id}</div>
          <div style={{ fontSize: 12, color: 'var(--slate)', marginBottom: 6 }}>
            {tooltip.hospital.location?.city}, {tooltip.hospital.location?.state}
          </div>
          <div style={{ fontSize: 12 }}>
            <span style={{ color: 'var(--green)' }}>Available: {tooltip.hospital.beds?.available ?? '?'}</span>
            {' / '}
            <span style={{ color: 'var(--slate)' }}>Total: {tooltip.hospital.beds?.total ?? '?'}</span>
          </div>
          {tooltip.hospital.fees?.opd > 0 && (
            <div style={{ fontSize: 12, color: 'var(--teal)', marginTop: 3 }}>
              OPD: ₹{tooltip.hospital.fees.opd} · ICU: ₹{tooltip.hospital.fees.icu}/day
            </div>
          )}
          <div style={{ fontSize: 11, color: 'var(--slate)', marginTop: 4, fontFamily: 'monospace' }}>
            Node: {tooltip.hospital.id}
          </div>
        </div>
      )}
    </div>
  );
};

export default GraphViz;
